# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.hyperbolic._peeloff_ipi","kind":"function","src_hash":"a176505b9a682d5a","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"_peeloff_ipi(arg)","rhs":"split arg into two parts, a \"rest\" and a multiple of $i\\pi$. this assumes arg to be an ``add``. the multiple of $i\\pi$ returned in the second position is always a ``rational``","over":{"base":"Any"},"name":"_peeloff_ipi_correct"},"guarantee":"split arg into two parts, a \"rest\" and a multiple of $i\\pi$. this assumes arg to be an ``add``. the multiple of $i\\pi$ returned in the second position is always a ``rational``","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.hyperbolic._peeloff_ipi_correct","statement":"Path(_peeloff_ipi(x), split arg into two parts, a \"rest\" and a multiple of $i\\pi$. this assumes arg to be an ``add``. the multiple of $i\\pi$ returned in the second position is always a ``rational``)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2857585c33a78a76"}
def _peeloff_ipi(arg):
    r"""
    Split ARG into two parts, a "rest" and a multiple of $I\pi$.
    This assumes ARG to be an ``Add``.
    The multiple of $I\pi$ returned in the second position is always a ``Rational``.

    Examples
    ========

    >>> from sympy.functions.elementary.hyperbolic import _peeloff_ipi as peel
    >>> from sympy import pi, I
    >>> from sympy.abc import x, y
    >>> peel(x + I*pi/2)
    (x, 1/2)
    >>> peel(x + I*2*pi/3 + I*pi*y)
    (x + I*pi*y + I*pi/6, 1/2)
    """
    ipi = pi*I
    for a in Add.make_args(arg):
        if a == ipi:
            K = S.One
            break
        elif a.is_Mul:
            K, p = a.as_two_terms()
            if p == ipi and K.is_Rational:
                break
    else:
        return arg, S.Zero

    m1 = (K % S.Half)
    m2 = K - m1
    return arg - m2*ipi, m2


